mapper.select:
select t.id, t.task_code, t.name, t.parent_task_id, t.milestone_id, m.name as milestone_name, t.task_type, t.status, t.priority, t.progress, t.assignee_id, u.real_name as assignee_name, t.planned_start_date, t.planned_end_date, t.deadline_date, t.constraint_type, t.constraint_date, t.actual_start_date, t.actual_end_date, t.planned_hours, t.actual_hours, t.sort_order, t.remark, t.description from project_task t left join sys_user u on u.id = t.assignee_id left join milestone m on m.id = t.milestone_id and m.is_deleted = 0 where t.project_id = #{projectId} and t.is_deleted = 0
and t.assignee_id = #{query.assigneeId}
and t.status = #{query.status}
and t.milestone_id = #{query.milestoneId}
and (t.name like concat('%', #{query.keyword}, '%') or t.task_code like concat('%', #{query.keyword}, '%'))
order by case when t.sort_order is null then 1 else 0 end, t.sort_order asc, t.id asc

select id, project_id, task_id, user_id, content, reply_to_id, created_at, updated_at, is_deleted
from task_comment
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

