mapper.update:
update project_task
set is_deleted = 1,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{taskId}
  and is_deleted = 0

update project_task
set status = #{status},
    progress = #{progress},
    assignee_id = #{assigneeId},
    remark = #{remark},
    actual_start_date = case
        when #{actualStartDate} is not null and actual_start_date is null then #{actualStartDate}
        else actual_start_date
    end,
    actual_end_date = case
        when #{status} = 'DONE' then #{actualEndDate}
        else null
    end,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{taskId}
  and is_deleted = 0

update project_task
set status = #{status},
    progress = #{progress},
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{taskId}
  and is_deleted = 0

update project_task
set actual_hours = #{actualHours},
    actual_cost = #{actualCost},
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{taskId}
  and is_deleted = 0

